  ('real-estate-moex-02276', 'real-estate', 'real-estate-moex-099-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依都市計畫法之規定，都市計畫經發布實施後，在某些情事發生時，當地直轄市、縣（市）（局）政府或鄉、鎮、縣轄市公所， 應視實際情況迅行變更，下列何者不屬之？', '["因戰爭、地震、水災、風災、火災或其他重大事變遭受損壞時", "為避免重大災害之發生時", "為適應國防或經濟發展之需要時", "為保育生態環境及歷史遺跡之需要時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "9833770e63fc", "answer_pdf_sha1": "6c1dc0520ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
